import React, { useMemo, useState } from 'react';
import { useNavigate, useParams, useLocation } from 'react-router-dom';
import {
  Button,
  Input,
  Select,
  Tabs,
  dispatchAppToast,
  type Tab,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { TeamDto } from '../../../services/ns/models';
import { CatalogCompanyField } from '../../../components/catalog/CatalogCompanyField';
import {
  EmployeeBankGrid,
  EmployeeContactGrid,
  EmployeeContractGrid,
  EmployeeDependentGrid,
  EmployeeQualificationGrid,
  EmployeeSalaryGrid,
} from '../../../components/ns/employee/EmployeeDetailGrids';
import gridStyles from '../../../components/ns/employee/EmployeeDetailGrids.module.css';
import { DocumentFormHeader } from '../../../components/layout';
import {
  nhanVienPageLabels as labels,
  REGION_ZONE_OPTIONS,
} from '../../../constants/nhanVienPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useHrEmployeePermissions } from '../../../hooks/useHrPermissions';
import {
  HR_EMPLOYEES_CATALOG_KIND,
  masterCodeService,
} from '../../../services/master/masterCodeService';
import df from '../../../styles/documentForm.module.css';
import {
  countActiveDependents,
  mapBankLinesFromDto,
  mapContactLinesFromDto,
  mapContractLinesFromDto,
  mapDependentLinesFromDto,
  mapQualificationLinesFromDto,
  ensureSalaryLinesFromEmployee,
  pickCurrentSalaryLine,
  toBankPayload,
  toContactPayload,
  toContractPayload,
  toDependentPayload,
  toQualificationPayload,
  toSalaryPayload,
  type EmployeeBankAccountLine,
  type EmployeeContactLine,
  type EmployeeContractLine,
  type EmployeeDependentLine,
  type EmployeeQualificationLine,
  type EmployeeSalaryLine,
} from '../../../services/ns/employeeDetailModels';
import { DEPARTMENT_FIELD_LABEL } from '../../../utils/departmentField';
import { formSelectFieldLock, formTextFieldLock } from '../../../utils/formViewLock';
import { DepartmentLookupField } from '../../../components/ns/employee/DepartmentLookupField';
import { EmployeeGroupLookupField } from '../../../components/ns/employee/EmployeeGroupLookupField';
import { useEmployeeGroupFormFields } from '../../../hooks/useEmployeeGroupFormFields';
import styles from './NhanVienFormPage.module.css';

const TEST_ID = 'erp-nhan-vien-form';

const TYPE_OPTIONS = [
  { value: 'TimeContract', label: 'Thời gian' },
  { value: 'PieceRate', label: 'Khoán' },
  { value: 'Seasonal', label: 'Thời vụ' },
];

const DETAIL_TABS: Tab[] = [
  { id: 'salary', label: labels.tabSalary },
  { id: 'bank', label: labels.tabBank },
  { id: 'qualification', label: labels.tabQualification },
  { id: 'contract', label: labels.tabContract },
  { id: 'contact', label: labels.tabContactDependent },
  { id: 'legal', label: labels.tabLegal },
];

const emptyForm = {
  code: '',
  fullName: '',
  type: 'TimeContract',
  departmentId: '',
  departmentCode: '',
  departmentName: '',
  teamId: '',
  phone: '',
  email: '',
  position: '',
  address: '',
  bankAccount: '',
  bankName: '',
  joinDate: '',
  leaveDate: '',
  isActive: true,
  legacyCode: '',
  citizenId: '',
  personalTaxCode: '',
  socialInsuranceCode: '',
  regionZone: 1,
  employeeGroup1Code: '',
  employeeGroup1Name: '',
  employeeGroup1Id: '',
  employeeGroup2Code: '',
  employeeGroup2Name: '',
  employeeGroup2Id: '',
  employeeGroup3Code: '',
  employeeGroup3Name: '',
  employeeGroup3Id: '',
  employeeGroup4Code: '',
  employeeGroup4Name: '',
  employeeGroup4Id: '',
};

type FormState = typeof emptyForm;

function clearEmployeeGroupsFromSlot(fromSlot: number): Partial<FormState> {
  if (fromSlot > 4) return {};
  const patch: Record<string, string> = {};
  for (let s = fromSlot; s <= 4; s += 1) {
    patch[`employeeGroup${s}Code`] = '';
    patch[`employeeGroup${s}Name`] = '';
    patch[`employeeGroup${s}Id`] = '';
  }
  return patch as Partial<FormState>;
}

async function resolveEmployeeGroupIds(
  groups: Array<{ slot: number; code: string }>,
): Promise<Partial<FormState>> {
  const patch: Record<string, string> = {};
  await Promise.all(
    groups.map(async ({ slot, code }) => {
      const trimmed = code.trim();
      if (!trimmed) return;
      const res = await hrService.getEmployeeGroups({
        slot,
        search: trimmed,
        isActive: true,
        pageSize: 50,
      });
      const match = res.items.find(g => g.code === trimmed);
      if (match) patch[`employeeGroup${slot}Id`] = match.id;
    }),
  );
  return patch as Partial<FormState>;
}

const NhanVienFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const perms = useHrEmployeePermissions();
  const { fields: groupFormFields } = useEmployeeGroupFormFields();
  const startInEditMode = (location.state as { startInEditMode?: boolean } | null)?.startInEditMode === true;
  const viewOnly = isEdit && !startInEditMode;

  const [activeTab, setActiveTab] = useState('salary');
  const [form, setForm] = useState<FormState>(emptyForm);
  const [teams, setTeams] = useState<TeamDto[]>([]);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [fullNameError, setFullNameError] = useState('');
  const [codePreview, setCodePreview] = useState<string>(labels.codePreviewFallback);
  const [companyName, setCompanyName] = useState<string | undefined>();
  const [bankLines, setBankLines] = useState<EmployeeBankAccountLine[]>([]);
  const [qualificationLines, setQualificationLines] = useState<EmployeeQualificationLine[]>([]);
  const [contractLines, setContractLines] = useState<EmployeeContractLine[]>([]);
  const [contactLines, setContactLines] = useState<EmployeeContactLine[]>([]);
  const [salaryLines, setSalaryLines] = useState<EmployeeSalaryLine[]>([]);
  const [dependentLines, setDependentLines] = useState<EmployeeDependentLine[]>([]);

  const activeDependentCount = useMemo(() => countActiveDependents(dependentLines), [dependentLines]);

  const set = <K extends keyof FormState>(key: K, value: FormState[K]) =>
    setForm(prev => ({ ...prev, [key]: value }));

  React.useEffect(() => {
    if (isEdit) return;
    let cancelled = false;
    const t = setTimeout(() => {
      masterCodeService
        .getFormatPreview(HR_EMPLOYEES_CATALOG_KIND)
        .then(p => {
          if (!cancelled && p.formatPreview) setCodePreview(p.formatPreview);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [isEdit]);

  React.useEffect(() => {
    if (isEdit) return;
    let cancelled = false;
    const t = setTimeout(() => {
      hrService
        .getEmployees({ page: 1, pageSize: 1 })
        .then(res => {
          if (!cancelled && res.items[0]?.companyName) {
            setCompanyName(res.items[0].companyName);
          }
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [isEdit]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService
        .getTeams(form.departmentId || undefined)
        .then(list => {
          if (!cancelled) setTeams(list);
        })
        .catch(() => {
          if (!cancelled) setTeams([]);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [form.departmentId]);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getEmployee(id)
        .then(async emp => {
          if (cancelled) return;
          const baseForm: FormState = {
              code: emp.code,
              fullName: emp.fullName,
              type: emp.type,
              departmentId: emp.departmentId ?? '',
              departmentCode: '',
              departmentName: emp.departmentName ?? '',
              teamId: emp.teamId ?? '',
              phone: emp.phone ?? '',
              email: emp.email ?? '',
              position: emp.position ?? '',
              address: emp.address ?? '',
              bankAccount: emp.bankAccount ?? '',
              bankName: emp.bankName ?? '',
              joinDate: emp.joinDate ? emp.joinDate.slice(0, 10) : '',
              leaveDate: emp.leaveDate ? emp.leaveDate.slice(0, 10) : '',
              isActive: emp.isActive,
              legacyCode: emp.legacyCode ?? '',
              citizenId: emp.citizenId ?? '',
              personalTaxCode: emp.personalTaxCode ?? '',
              socialInsuranceCode: emp.socialInsuranceCode ?? '',
              regionZone: emp.regionZone ?? 1,
              employeeGroup1Code: emp.employeeGroup1Code ?? '',
              employeeGroup1Name: emp.employeeGroup1Name ?? '',
              employeeGroup1Id: '',
              employeeGroup2Code: emp.employeeGroup2Code ?? '',
              employeeGroup2Name: emp.employeeGroup2Name ?? '',
              employeeGroup2Id: '',
              employeeGroup3Code: emp.employeeGroup3Code ?? '',
              employeeGroup3Name: emp.employeeGroup3Name ?? '',
              employeeGroup3Id: '',
              employeeGroup4Code: emp.employeeGroup4Code ?? '',
              employeeGroup4Name: emp.employeeGroup4Name ?? '',
              employeeGroup4Id: '',
            };
          setForm(baseForm);
          const idPatch = await resolveEmployeeGroupIds([
            { slot: 1, code: baseForm.employeeGroup1Code },
            { slot: 2, code: baseForm.employeeGroup2Code },
            { slot: 3, code: baseForm.employeeGroup3Code },
            { slot: 4, code: baseForm.employeeGroup4Code },
          ]);
          if (!cancelled) {
            setForm(prev => ({ ...prev, ...idPatch }));
            setCompanyName(emp.companyName);
            setBankLines(mapBankLinesFromDto(emp.bankAccounts));
            setQualificationLines(mapQualificationLinesFromDto(emp.qualifications));
            setContractLines(mapContractLinesFromDto(emp.contracts));
            setContactLines(mapContactLinesFromDto(emp.contacts));
            setSalaryLines(ensureSalaryLinesFromEmployee(emp));
            setDependentLines(mapDependentLinesFromDto(emp.dependents));
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadFormError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [id, dispatch]);

  const teamOptions = useMemo(
    () => [
      { value: '', label: labels.teamPlaceholder },
      ...teams.map(t => ({ value: t.id, label: `${t.code} — ${t.name}` })),
    ],
    [teams],
  );

  const buildPayload = () => {
    const currentSalary = pickCurrentSalaryLine(salaryLines);
    return {
      fullName: form.fullName.trim(),
      type: form.type,
      departmentId: form.departmentId || undefined,
      teamId: form.teamId || undefined,
      phone: form.phone || undefined,
      email: form.email || undefined,
      position: form.position || undefined,
      address: form.address || undefined,
      bankAccount: form.bankAccount || undefined,
      bankName: form.bankName || undefined,
      baseSalary: currentSalary?.baseSalary ?? 0,
      contractSalary: currentSalary?.contractSalary ?? 0,
      positionAllowance: currentSalary?.positionAllowance ?? 0,
      lunchAllowance: currentSalary?.lunchAllowance ?? 0,
      joinDate: form.joinDate || undefined,
      citizenId: form.citizenId || undefined,
      personalTaxCode: form.personalTaxCode || undefined,
      socialInsuranceCode: form.socialInsuranceCode || undefined,
      numberOfDependents: activeDependentCount,
      regionZone: Number(form.regionZone) || 1,
      legacyCode: form.legacyCode.trim() || undefined,
      employeeGroup1Code: form.employeeGroup1Code.trim() || undefined,
      employeeGroup2Code: form.employeeGroup2Code.trim() || undefined,
      employeeGroup3Code: form.employeeGroup3Code.trim() || undefined,
      employeeGroup4Code: form.employeeGroup4Code.trim() || undefined,
      bankAccounts: toBankPayload(bankLines),
      qualifications: toQualificationPayload(qualificationLines),
      contracts: toContractPayload(contractLines),
      contacts: toContactPayload(contactLines),
      salaryLines: toSalaryPayload(salaryLines),
      dependents: toDependentPayload(dependentLines),
    };
  };

  const handleSave = async () => {
    if (!form.fullName.trim()) {
      setFullNameError(labels.fullNameRequired);
      document.getElementById(`${TEST_ID}-section-main`)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      dispatchAppToast(dispatch, { message: labels.fullNameRequired, type: 'error' });
      return;
    }
    setFullNameError('');
    if (!perms.canCreate && !isEdit) return;
    if (isEdit && !perms.canUpdate) return;

    setSaving(true);
    try {
      const payload = buildPayload();
      if (isEdit && id) {
        await hrService.updateEmployee(id, {
          ...payload,
          isActive: form.isActive,
          leaveDate: form.leaveDate || undefined,
        });
        dispatchAppToast(dispatch, { message: labels.updateSuccess, type: 'success' });
      } else {
        await hrService.createEmployee(payload);
        dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      }
      navigate('/ns/nhan-vien');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleDepartmentChange = (departmentId: string, departmentCode: string, departmentName: string) => {
    setForm(prev => ({
      ...prev,
      departmentId,
      departmentCode,
      departmentName,
      teamId: '',
    }));
  };

  const handleDepartmentClear = () => {
    setForm(prev => ({
      ...prev,
      departmentId: '',
      departmentCode: '',
      departmentName: '',
      teamId: '',
    }));
  };

  if (loading) {
    return <div className={df.loading}>Đang tải...</div>;
  }

  const canSave = isEdit ? perms.canUpdate : perms.canCreate;
  const viewSectionClass = viewOnly ? df.viewReadOnlySection : undefined;
  const textLock = formTextFieldLock(viewOnly);
  const selectLock = formSelectFieldLock(viewOnly);

  const codeRow = isEdit && form.code ? (
    <div className={df.row4}>
      <div className={df.field}>
        <label className={df.label}>Mã NV</label>
        <Input value={form.code} disabled readOnly data-testid="erp-nhan-vien-form-code" />
      </div>
      {form.legacyCode ? (
        <div className={df.field}>
          <label className={df.label}>Mã gốc</label>
          <span
            data-testid="erp-nhan-vien-form-legacyCode"
            style={{ color: 'var(--linm-color-legacy-code, #ca8a04)', fontSize: 14 }}
          >
            Mã cũ: {form.legacyCode}
          </span>
        </div>
      ) : null}
    </div>
  ) : !isEdit ? (
    <div className={df.row4}>
      <div className={df.field}>
        <label className={df.label}>{labels.codeFieldLabel}</label>
        <Input
          value=""
          disabled
          readOnly
          placeholder={codePreview}
          data-testid="erp-nhan-vien-form-code-preview"
        />
      </div>
      <div className={df.field}>
        <label className={df.label}>Mã gốc</label>
        <Input
          value={form.legacyCode}
          onChange={e => set('legacyCode', e.target.value)}
            {...textLock}
            placeholder="Mã hệ thống cũ (tùy chọn)"
          data-testid="erp-nhan-vien-form-legacyCode-input"
        />
      </div>
    </div>
  ) : null;

  const mainSection = (
    <div className={viewSectionClass}>
      {codeRow}
      <div className={df.row4}>
        <div className={df.field}>
          <label className={df.label}>Họ tên *</label>
          <Input
            value={form.fullName}
            onChange={e => {
              set('fullName', e.target.value);
              if (fullNameError) setFullNameError('');
            }}
            {...textLock}
            data-testid="erp-nhan-vien-form-fullName"
          />
          {fullNameError ? (
            <span style={{ color: 'var(--ds-color-error, #C33A00)', fontSize: 12 }}>{fullNameError}</span>
          ) : null}
        </div>
        <div className={df.field}>
          <label className={df.label}>Loại HĐ *</label>
          <Select
            value={form.type}
            onChange={e => set('type', e.target.value)}
            options={TYPE_OPTIONS}
            {...selectLock}
          />
        </div>
        <div className={df.field}>
          <label className={df.label}>{DEPARTMENT_FIELD_LABEL}</label>
          <DepartmentLookupField
            departmentId={form.departmentId}
            departmentCode={form.departmentCode}
            departmentName={form.departmentName}
            disabled={viewOnly}
            onChange={handleDepartmentChange}
            onClear={handleDepartmentClear}
            testId={`${TEST_ID}-departmentId`}
          />
        </div>
        <div className={df.field}>
          <label className={df.label}>Tổ</label>
          <Select
            value={form.teamId}
            onChange={e => set('teamId', e.target.value)}
            options={teamOptions}
            disabled={viewOnly ? true : !form.departmentId}
          />
        </div>
      </div>
      <div className={df.row4}>
        {groupFormFields.map(field => {
          const codeKey = `employeeGroup${field.slot}Code` as keyof FormState;
          const nameKey = `employeeGroup${field.slot}Name` as keyof FormState;
          const idKey = `employeeGroup${field.slot}Id` as keyof FormState;
          const parentGroupIdForLookup =
            field.slot > 1
              ? String(form[`employeeGroup${field.slot - 1}Id` as keyof FormState] ?? '') ||
                undefined
              : undefined;
          return (
            <div key={field.key} className={df.field}>
              <label className={df.label}>{field.label}</label>
              <EmployeeGroupLookupField
                slot={field.slot}
                parentGroupId={parentGroupIdForLookup}
                value={String(form[codeKey] ?? '')}
                displayName={String(form[nameKey] ?? '')}
                disabled={viewOnly}
                onChange={(code, name, groupId) => {
                  setForm(prev => ({
                    ...prev,
                    [codeKey]: code,
                    [nameKey]: name,
                    [idKey]: groupId,
                    ...clearEmployeeGroupsFromSlot(field.slot + 1),
                  }));
                }}
                onClear={() => {
                  setForm(prev => ({
                    ...prev,
                    [codeKey]: '',
                    [nameKey]: '',
                    [idKey]: '',
                    ...clearEmployeeGroupsFromSlot(field.slot + 1),
                  }));
                }}
                testId={`${TEST_ID}-group-${field.slot}`}
              />
            </div>
          );
        })}
      </div>
      <div className={df.row4}>
        <div className={df.field}>
          <label className={df.label}>Ngày vào làm</label>
          <Input
            type="date"
            value={form.joinDate}
            onChange={e => set('joinDate', e.target.value)}
            {...textLock}
          />
        </div>
        {isEdit ? (
          <div className={df.field}>
            <label className={df.label}>{labels.leaveDateLabel}</label>
            <Input
              type="date"
              value={form.leaveDate}
              onChange={e => set('leaveDate', e.target.value)}
              {...textLock}
            />
          </div>
        ) : null}
        <div className={df.field}>
          <label className={df.label}>Điện thoại</label>
          <Input value={form.phone} onChange={e => set('phone', e.target.value)} {...textLock} />
        </div>
        <div className={df.field}>
          <label className={df.label}>Email</label>
          <Input value={form.email} onChange={e => set('email', e.target.value)} {...textLock} />
        </div>
      </div>
      <div className={df.row4}>
        <div className={df.field}>
          <label className={df.label}>Chức vụ</label>
          <Input value={form.position} onChange={e => set('position', e.target.value)} {...textLock} />
        </div>
        <div className={df.field} style={{ gridColumn: 'span 3' }}>
          <label className={df.label}>{labels.addressLabel}</label>
          <Input
            value={form.address}
            onChange={e => set('address', e.target.value)}
            {...textLock}
            data-testid="erp-nhan-vien-form-address"
          />
        </div>
      </div>
      {isEdit ? (
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Trạng thái</label>
            <Select
              value={form.isActive ? 'true' : 'false'}
              onChange={e => set('isActive', e.target.value === 'true')}
              options={[
                { value: 'true', label: 'Hoạt động' },
                { value: 'false', label: 'Nghỉ việc' },
              ]}
              {...selectLock}
            />
          </div>
        </div>
      ) : null}
      <CatalogCompanyField testIdPrefix={TEST_ID} companyName={companyName} />
    </div>
  );

  const salaryTab = (
    <EmployeeSalaryGrid
      rows={salaryLines}
      viewOnly={viewOnly}
      onChange={setSalaryLines}
      testIdPrefix={TEST_ID}
    />
  );

  const bankTab = (
    <>
      <div className={df.row4}>
        <div className={df.field}>
          <label className={df.label}>{labels.bankAccountLabel} (chính)</label>
          <Input
            value={form.bankAccount}
            onChange={e => set('bankAccount', e.target.value)}
            {...textLock}
            data-testid="erp-nhan-vien-form-bankAccount"
          />
        </div>
        <div className={df.field}>
          <label className={df.label}>{labels.bankNameLabel} (chính)</label>
          <Input
            value={form.bankName}
            onChange={e => set('bankName', e.target.value)}
            {...textLock}
            data-testid="erp-nhan-vien-form-bankName"
          />
        </div>
      </div>
      <EmployeeBankGrid
        rows={bankLines}
        viewOnly={viewOnly}
        onChange={setBankLines}
        testIdPrefix={TEST_ID}
      />
    </>
  );

  const legalTab = (
    <>
      <div className={df.row4}>
        <div className={df.field}>
          <label className={df.label}>{labels.citizenIdLabel}</label>
          <Input
            value={form.citizenId}
            onChange={e => set('citizenId', e.target.value)}
            {...textLock}
            data-testid="erp-nhan-vien-form-citizenId"
          />
        </div>
        <div className={df.field}>
          <label className={df.label}>{labels.personalTaxCodeLabel}</label>
          <Input
            value={form.personalTaxCode}
            onChange={e => set('personalTaxCode', e.target.value)}
            {...textLock}
            maxLength={10}
            data-testid="erp-nhan-vien-form-personalTaxCode"
          />
        </div>
        <div className={df.field}>
          <label className={df.label}>{labels.socialInsuranceCodeLabel}</label>
          <Input
            value={form.socialInsuranceCode}
            onChange={e => set('socialInsuranceCode', e.target.value)}
            {...textLock}
            data-testid="erp-nhan-vien-form-socialInsuranceCode"
          />
        </div>
        <div className={df.field}>
          <label className={df.label}>{labels.numberOfDependentsLabel}</label>
          <Input
            value={String(activeDependentCount)}
            disabled
            readOnly
            data-testid="erp-nhan-vien-form-numberOfDependents"
          />
          <span style={{ fontSize: 12, color: 'var(--ds-color-text-tertiary, #6b7280)' }}>
            {labels.dependentCountHint}
          </span>
        </div>
      </div>
      <div className={df.row4}>
        <div className={df.field}>
          <label className={df.label}>{labels.regionZoneLabel}</label>
          <Select
            value={String(form.regionZone)}
            onChange={e => set('regionZone', Number(e.target.value))}
            options={[...REGION_ZONE_OPTIONS]}
            {...selectLock}
            data-testid="erp-nhan-vien-form-regionZone"
          />
        </div>
      </div>
    </>
  );

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/ns/nhan-vien')}
        title={isEdit ? (viewOnly ? 'Xem nhân viên' : 'Sửa nhân viên') : 'Thêm nhân viên mới'}
        isNew={!isEdit}
        isReadOnly={viewOnly}
        saving={saving}
        saveLabel="Tạo nhân viên"
        saveEditLabel="Lưu thay đổi"
        onSave={canSave && !viewOnly ? handleSave : undefined}
      />

      <div className={styles.formSection} id={`${TEST_ID}-section-main`} data-testid={`${TEST_ID}-section-main`}>
        <h2 className={df.sectionTitle}>{labels.sectionMain}</h2>
        {mainSection}
      </div>

      <div className={styles.formSection} data-testid={`${TEST_ID}-section-detail`}>
        <h2 className={df.sectionTitle}>{labels.sectionDetail}</h2>
        <div className={styles.tabBar} data-testid="erp-nhan-vien-form-tabs">
          <Tabs
            tabs={DETAIL_TABS}
            activeTab={activeTab}
            onTabChange={setActiveTab}
            variant="underline"
          />
        </div>
        <div className={[styles.tabPanel, viewSectionClass].filter(Boolean).join(' ')}>
          {activeTab === 'salary' ? salaryTab : null}
          {activeTab === 'bank' ? bankTab : null}
          {activeTab === 'qualification' ? (
            <EmployeeQualificationGrid
              rows={qualificationLines}
              viewOnly={viewOnly}
              onChange={setQualificationLines}
              testIdPrefix={TEST_ID}
            />
          ) : null}
          {activeTab === 'contract' ? (
            <EmployeeContractGrid
              rows={contractLines}
              viewOnly={viewOnly}
              onChange={setContractLines}
              testIdPrefix={TEST_ID}
            />
          ) : null}
          {activeTab === 'contact' ? (
            <div className={gridStyles.subsection}>
              <div>
                <h3 className={gridStyles.subsectionTitle}>{labels.contactEmergencyTitle}</h3>
                <EmployeeContactGrid
                  rows={contactLines}
                  viewOnly={viewOnly}
                  onChange={setContactLines}
                  testIdPrefix={TEST_ID}
                />
              </div>
              <div>
                <h3 className={gridStyles.subsectionTitle}>{labels.dependentTitle}</h3>
                <EmployeeDependentGrid
                  rows={dependentLines}
                  viewOnly={viewOnly}
                  onChange={setDependentLines}
                  testIdPrefix={TEST_ID}
                />
              </div>
            </div>
          ) : null}
          {activeTab === 'legal' ? legalTab : null}
        </div>
      </div>

      {viewOnly && perms.canUpdate ? (
        <div className={df.footer}>
          <Button
            variant="primary"
            onClick={() =>
              navigate(`/ns/nhan-vien/${id}`, { state: { startInEditMode: true }, replace: true })
            }
          >
            Sửa
          </Button>
        </div>
      ) : null}
    </div>
  );
};

export default NhanVienFormPage;
