import React, { useCallback, useMemo } from 'react';
import { SearchInput, type SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { useCatalogSearchConfig } from '../../catalog/catalogUiSchema/useCatalogSearchConfig';
import { hrEndpoint } from '../../../services/ns/endpoint';
import type { HrEmployeeGroupDto } from '../../../services/ns/models';

export const HR_EMPLOYEE_GROUPS_CATALOG_KIND = 'hr-employee-groups';

type Props = {
  slot: number;
  value: string;
  displayName?: string;
  /** Nhóm cha slot trước — lọc con + nhóm cùng slot không parent. */
  parentGroupId?: string;
  disabled?: boolean;
  onChange: (code: string, name: string, groupId: string) => void;
  onClear: () => void;
  testId?: string;
};

function buildFallbackGroupSearchConfig(
  slot: number,
  search: (params: { search?: string; page?: number; pageSize?: number }) => ReturnType<
    typeof hrEndpoint.getEmployeeGroups
  >,
): SearchInputConfig<HrEmployeeGroupDto> {
  return {
    api: {
      getItemKey: item => item.id,
      search: async ({ search: term, page, pageSize }) => {
        const data = await search({ search: term, page, pageSize });
        const size = data.pageSize || 20;
        const totalPages = Math.max(1, Math.ceil(data.totalCount / size));
        return { items: data.items, page: data.page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
    },
    columns: [
      {
        key: 'code',
        variant: 'badge',
        width: '7rem',
        render: item => item.code || '—',
      },
      {
        key: 'name',
        variant: 'primary',
        render: item => item.name || '—',
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã nhóm' },
        { key: 'name', label: 'Tên nhóm' },
      ],
    },
    dropdownMatch: 'row',
    dropdownMinWidth: '22rem',
    texts: { empty: 'Không có nhóm nào' },
  };
}

export const EmployeeGroupLookupField: React.FC<Props> = ({
  slot,
  value,
  displayName,
  parentGroupId,
  disabled,
  onChange,
  onClear,
  testId,
}) => {
  const search = useCallback(
    (params: { search?: string; page?: number; pageSize?: number }) =>
      hrEndpoint.getEmployeeGroups({
        slot,
        search: params.search,
        isActive: true,
        parentId: parentGroupId || undefined,
        page: params.page,
        pageSize: params.pageSize,
      }),
    [slot, parentGroupId],
  );

  const { config: schemaConfig, loading } = useCatalogSearchConfig<HrEmployeeGroupDto>(
    HR_EMPLOYEE_GROUPS_CATALOG_KIND,
    search,
    item => item.id,
    {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
    },
  );

  const fallbackConfig = useMemo(
    () => buildFallbackGroupSearchConfig(slot, search),
    [slot, search],
  );

  const effectiveConfig = schemaConfig ?? fallbackConfig;

  const primaryDisplay = useMemo(() => {
    if (!value) return '';
    return displayName ? `${value} — ${displayName}` : value;
  }, [value, displayName]);

  return (
    <SearchInput
      config={effectiveConfig}
      value={value}
      primaryDisplay={primaryDisplay}
      onChange={item => onChange(String(item.code), String(item.name), String(item.id))}
      onClear={onClear}
      disabled={disabled || loading}
      showLabel={false}
      showSecondaryInput={false}
      placeholder={loading ? 'Đang tải...' : 'Mã hoặc tên nhóm...'}
      data-testid={testId}
    />
  );
};
