import React from 'react';
import { Button, Checkbox, Input, MoneyInput, Select } from '@linm-soft-org/linm-web-common-components';
import type {
  EmployeeBankAccountLine,
  EmployeeContactLine,
  EmployeeContractLine,
  EmployeeDependentLine,
  EmployeeQualificationLine,
  EmployeeSalaryLine,
} from '../../../services/ns/employeeDetailModels';
import {
  detailGridSelectLock,
  detailGridTextLock,
  formSelectFieldLock,
} from '../../../utils/formViewLock';
import df from '../../../styles/documentForm.module.css';
import styles from './EmployeeDetailGrids.module.css';

const CONTRACT_TYPE_OPTIONS = [
  { value: 'TimeContract', label: 'Thời gian' },
  { value: 'PieceRate', label: 'Khoán' },
  { value: 'Seasonal', label: 'Thời vụ' },
  { value: 'Probation', label: 'Thử việc' },
];

type GridProps<T> = {
  rows: T[];
  viewOnly: boolean;
  onChange: (rows: T[]) => void;
  testIdPrefix: string;
};

function gridWrapClass(viewOnly: boolean): string {
  return [styles.gridWrap, viewOnly ? df.viewReadOnlySection : ''].filter(Boolean).join(' ');
}

function EmptyGridRow({ colSpan }: { colSpan: number }): React.ReactElement {
  return (
    <tr>
      <td colSpan={colSpan} className={styles.emptyRow}>
        Chưa có dữ liệu
      </td>
    </tr>
  );
}

const emptyBank = (): EmployeeBankAccountLine => ({
  bankName: '',
  accountNumber: '',
  branchName: '',
  isPrimary: false,
  sortOrder: 0,
});

const emptyQualification = (): EmployeeQualificationLine => ({
  title: '',
  institution: '',
  issuedDate: '',
  note: '',
  sortOrder: 0,
});

const emptyContract = (): EmployeeContractLine => ({
  contractNo: '',
  contractType: 'TimeContract',
  startDate: '',
  endDate: '',
  salary: 0,
  note: '',
  sortOrder: 0,
});

const emptyContact = (): EmployeeContactLine => ({
  fullName: '',
  relationship: '',
  phone: '',
  email: '',
  address: '',
  isEmergency: false,
  sortOrder: 0,
});

export const EmployeeBankGrid: React.FC<GridProps<EmployeeBankAccountLine>> = ({
  rows,
  viewOnly,
  onChange,
  testIdPrefix,
}) => {
  const update = (idx: number, patch: Partial<EmployeeBankAccountLine>) =>
    onChange(rows.map((r, i) => (i === idx ? { ...r, ...patch } : r)));
  const textLock = detailGridTextLock(viewOnly);
  const selectLock = detailGridSelectLock(viewOnly);

  return (
    <div className={gridWrapClass(viewOnly)} data-testid={`${testIdPrefix}-bank-grid`}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th>Ngân hàng</th>
            <th>Số TK</th>
            <th>Chi nhánh</th>
            <th>Chính</th>
            <th />
          </tr>
        </thead>
        <tbody>
          {rows.length === 0 ? (
            <EmptyGridRow colSpan={5} />
          ) : (
            rows.map((row, idx) => (
              <tr key={row.id ?? `bank-${idx}`}>
                <td><Input value={row.bankName} {...textLock} onChange={e => update(idx, { bankName: e.target.value })} /></td>
                <td><Input value={row.accountNumber} {...textLock} onChange={e => update(idx, { accountNumber: e.target.value })} /></td>
                <td><Input value={row.branchName ?? ''} {...textLock} onChange={e => update(idx, { branchName: e.target.value })} /></td>
                <td>
                  <Checkbox
                    id={`${testIdPrefix}-bank-primary-${idx}`}
                    checked={row.isPrimary}
                    {...selectLock}
                    onChange={e => update(idx, { isPrimary: e.target.checked })}
                  />
                </td>
                <td>
                  {!viewOnly ? (
                    <Button variant="secondary" onClick={() => onChange(rows.filter((_, i) => i !== idx))}>Xóa</Button>
                  ) : null}
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
      {!viewOnly ? (
        <Button variant="secondary" onClick={() => onChange([...rows, emptyBank()])}>Thêm TK</Button>
      ) : null}
    </div>
  );
};

