const emptySalary = (): EmployeeSalaryLine => ({
  effectiveFrom: new Date().toISOString().slice(0, 10),
  effectiveTo: '',
  baseSalary: 0,
  contractSalary: 0,
  positionAllowance: 0,
  lunchAllowance: 0,
  note: '',
  sortOrder: 0,
});

